    for i in 0..<n {
        if chars[i] == "L" {
            count += 1
        }
        lCount[i] = count
    }

    // Compute suffix T counts
    count = 0
    for i in (0..<n).reversed() {
        if chars[i] == "T" {
            count += 1
        }
        tCount[i] = count
    }

    var original = 0
    var cPositions = [Int]()
    for i in 0..<n {
        if chars[i] == "C" {
            cPositions.append(i)
            if i > 0 && i < n - 1 {
                original += lCount[i - 1] * tCount[i + 1]
            }
        }
    }

    if cPositions.isEmpty {
        return 0
    }

    var maxIncrease = 0

    // Check inserting L
    var bestL = 0
    for cPos in cPositions {
        let leftL = cPos > 0 ? lCount[cPos - 1] : 0
        let rightT = cPos < n - 1 ? tCount[cPos + 1] : 0
        bestL = max(bestL, rightT)
    }
    maxIncrease = max(maxIncrease, bestL)

    // Check inserting C
    var bestC = 0
    for i in 0...n {
        let leftL: Int
        if i == 0 {
            leftL = 0
        } else {
            leftL = lCount[i - 1]
        }

        var rightT = 0
        if i < n {
            rightT = tCount[i]
        }

        bestC = max(bestC, leftL * rightT)
    }
    maxIncrease = max(maxIncrease, bestC)

    // Check inserting T
    var bestT = 0
    for cPos in cPositions {
        let leftL = cPos > 0 ? lCount[cPos - 1] : 0
        let rightT = cPos < n - 1 ? tCount[cPos + 1] : 0
        bestT = max(bestT, leftL)
    }
    maxIncrease = max(maxIncrease, bestT)

    return Int64(original + maxIncrease)
}
