            let increaseIfInsertC = (lCount[i] + (chars[i] == "L" ? 1 : 0)) * tCount[i]
            // Potential increase if we insert 'T' at current position
            let increaseIfInsertT = lCount[i] * (tCount[i] + (chars[i] == "T" ? 1 : 0))

            let currentMax = max(increaseIfInsertL, increaseIfInsertC, increaseIfInsertT)
            maxIncrease = max(maxIncrease, currentMax - lCount[i] * tCount[i+1])
        }
    }

    // Also consider inserting at the end
    let insertAtEndL = lCount[n] * 0
    let insertAtEndC = lCount[n] * 0
    let insertAtEndT = lCount[n] * 1
    let insertAtEndMax = max(insertAtEndL, insertAtEndC, insertAtEndT)
    maxIncrease = max(maxIncrease, insertAtEndMax)

    // Also consider inserting at the beginning
    let insertAtStartL = 1 * tCount[0]
    let insertAtStartC = 0 * tCount[0]
    let insertAtStartT = 0 * tCount[0]
    let insertAtStartMax = max(insertAtStartL, insertAtStartC, insertAtStartT)
    maxIncrease = max(maxIncrease, insertAtStartMax)

    let total = original + maxIncrease
    return Int64(total)
}
