```swift
import Foundation

func solve(s: String) -> Int64 {
    let chars = Array(s)
    let n = chars.count
    var lCount = [Int](repeating: 0, count: n + 1)
    var tCount = [Int](repeating: 0, count: n + 1)

    // Precompute the number of 'L's before each position
    for i in 0..<n {
        lCount[i+1] = lCount[i] + (chars[i] == "L" ? 1 : 0)
    }

    // Precompute the number of 'T's after each position
    for i in (0..<n).reversed() {
        tCount[i] = tCount[i+1] + (chars[i] == "T" ? 1 : 0)
    }

    var original = 0
    var maxIncrease = 0

    // Calculate original count and potential increases
    for i in 0..<n {
        if chars[i] == "C" {
            original += lCount[i] * tCount[i+1]

            // Potential increase by inserting 'L' before current position
            let increaseL = lCount[i] * tCount[i]
            // Potential increase by inserting 'C' at current position (same as inserting before)
            let increaseC = (lCount[i] + (chars[i] == "L" ? 1 : 0)) * tCount[i]
            // Potential increase by inserting 'T' after current position
            let increaseT = lCount[i+1] * (tCount[i+1] + (chars[i] == "T" ? 1 : 0))

            let currentMax = max(increaseL, increaseC, increaseT)
            maxIncrease = max(maxIncrease, currentMax - (lCount[i] * tCount[i+1]))
        }
    }

    // Also consider inserting at the beginning or end
    // Insert 'L' at the beginning
    let beginL = tCount[0]
    maxIncrease = max(maxIncrease, beginL)

    // Insert 'T' at the end
    let endT = lCount[n]
    maxIncrease = max(maxIncrease, endT)

    return Int64(original + maxIncrease)
}
